async function storeRefreshToken(refreshToken, payload) {
  const jti = hashToken(refreshToken);
  const key = `oauth:rt:${jti}`;
  await redis.set(key, JSON.stringify(payload), 'EX', REFRESH_TOKEN_TTL_SECONDS);
  return { jti, key };
}

async function getRefreshToken(refreshToken) {
  const jti = hashToken(refreshToken);
  const key = `oauth:rt:${jti}`;
  const val = await redis.get(key);
  if (!val) return null;
  const payload = JSON.parse(val);
  return { jti, payload };
}

async function touchRefreshTokenTTL(refreshToken) {
  const jti = hashToken(refreshToken);
  const key = `oauth:rt:${jti}`;
  await redis.expire(key, REFRESH_TOKEN_TTL_SECONDS);
}

function oauthError(res, status, error, description) {
  const body = { error };
  if (description) body.error_description = description;
  res.status(status).json(body);
}

